import React, { useState, useEffect } from "react";

import { ContactForm } from "../../components/contactForm/ContactForm";
import { TileList } from "../../components/tileList/TileList";

export const ContactsPage = (props) => {
  /*
  Define state variables for 
  contact info and duplicate check
  */
  const [name, setName] = useState('');
  const [duplicateName, setDuplicateName] = useState(false);
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    //Add contact info and clear data if the contact name is not a duplicate
  };

  /*
  Using hooks, check for contact name in the 
  contacts array variable in props
  */
  useEffect(() => {
    const array = props.contacts;
    //const nameInlist = array.includes(name);
    //alert(`Duplicate is ${nameInlist}`);
    alert(`Array is ${array}`);
  }, [name]);

  const handleChange = () => {
    //Check for duplicates whenever the name in the form changes and indicate the name is a duplicate

  };

  //const handleChange = ({ target }) => setName(target.value);

  return (
    <div>
      <section>
        <h2>Add Contact</h2> 
        <ContactForm>
          name={name} 
          setName={setName} 
          phone={phone}
          setPhone={setPhone}
          email={email} 
          setEmail={setEmail} 
          handleSubmit={handleSubmit}
        </ContactForm>
        <label htmlFor="name">Name:</label>
        <input type="text" id="name"></input>
        <label htmlFor="phone">Phone:</label>
        <input type="number" id="phone" value={phone}></input>
        <label htmlFor="email">Email:</label>
        <input type="text" id="email" value={email}></input>
      </section>
      <hr />
      <section>
        <h2>Contacts</h2>
        <TileList contacts={props.contacts}></TileList>
      </section>
    </div>
  );
};
